#include <bits/stdc++.h>
using namespace std;

int n;
int a[10005], b[10005], g[10005], k[10005];
int x, y;

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i] >> b[i] >> g[i] >> k[i];
    }
    cin >> x >> y;
    int ans = -1;
    for (int i = 0; i < n; i++) {
        int left = a[i];
        int right = a[i] + g[i];
        int top = b[i] + k[i];
        int bottom = b[i];
        if (left <= x && x <= right && top >= y && y >= bottom) {
            ans = i + 1;
        }
    }
    cout << ans;
    return 0;
}
